import { test, expect } from '@playwright/test';

test('header links should be clickable and route correctly', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  const links = [
    { name: 'okwasniewski', path: '/' },
    { name: 'blog', path: '/blog' },
    { name: 'portfolio', path: '/portfolio' },
    { name: 'videos', path: '/videos' },
    { name: 'contact', path: '/contact' }
  ];

  for (const link of links) {
    const locator = page.locator(`header a:has-text("${link.name}")`);
    await expect(locator).toBeVisible();

    // Verify pointer-events is not 'none'
    const pointerEvents = await locator.evaluate(el => getComputedStyle(el).pointerEvents);
    expect(pointerEvents).not.toBe('none');

    // This will fail due to the bug (pointer-events: none)
    await locator.click();
    await page.waitForURL(`**${link.path}`);
    expect(page.url()).toContain(link.path);

    // Go back to home if needed for next link
    if (link.path !== '/') await page.goto('http://localhost:3002/');
  }
});
